import os
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.common.keys import Keys
import pyautogui
import boto3
import json

# Set AWS credentials and region
AWS_ACCESS_KEY = 'YOUR_AWS_ACCESS_KEY'
AWS_SECRET_KEY = 'YOUR_AWS_SECRET_KEY'
AWS_REGION = 'us-west-2'

# Set S3 bucket name and URL prefix for screenshots
S3_BUCKET_NAME = 'your-bucket-name'
URL_PREFIX = 'https://your-website.com/screenshots/'

def take_screenshot(url):
    # Set Chrome options to run in headless mode
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--window-size=1920,1080')

    # Create a new instance of the Chrome driver
    driver = webdriver.Chrome(options=chrome_options)

    try:
        # Navigate to the given URL
        driver.get(url)

        # Take a full screenshot and save it as a PNG file
        screenshot = pyautogui.screenshot()
        screenshot.save('screenshot.png')

        # Upload the screenshot to S3
        s3_client = boto3.client('s3', aws_access_key_id=AWS_ACCESS_KEY,
                                 aws_secret_access_key=AWS_SECRET_KEY, region_name=AWS_REGION)
        s3_client.upload_file('screenshot.png', S3_BUCKET_NAME, f'{url}.png')

    except Exception as e:
        print(f'Error taking screenshot: {e}')

    finally:
        driver.quit()

def handle_request(event, context):
    url = event['url']
    take_screenshot(url)

if __name__ == '__main__':
    # For testing purposes
    url = 'https://www.example.com'
    take_screenshot(url)